10	bool TryParseConstantPattern(ClientContext &context, Expression &expr, string &constant_string) {
11		if (!expr.IsFoldable()) {
12			return false;
13		}
14		Value pattern_str = ExpressionExecutor::EvaluateScalar(context, expr);
15		if (!pattern_str.IsNull() && pattern_str.type().id() == LogicalTypeId::VARCHAR) {
16			constant_string = StringValue::Get(pattern_str);
17			return true;
18		}
19		return false;
20	}
