22	void ParseRegexOptions(const string &options, duckdb_re2::RE2::Options &result, bool *global_replace) {
23		for (idx_t i = 0; i < options.size(); i++) {
24			switch (options[i]) {
25			case 'c':
26				// case-sensitive matching
27				result.set_case_sensitive(true);
28				break;
29			case 'i':
30				// case-insensitive matching
31				result.set_case_sensitive(false);
32				break;
33			case 'l':
34				// literal matching
35				result.set_literal(true);
36				break;
37			case 'm':
38			case 'n':
39			case 'p':
40				// newline-sensitive matching
41				result.set_dot_nl(false);
42				break;
43			case 's':
44				// non-newline-sensitive matching
45				result.set_dot_nl(true);
46				break;
47			case 'g':
48				// global replace, only available for regexp_replace
49				if (global_replace) {
50					*global_replace = true;
51				} else {
52					throw InvalidInputException("Option 'g' (global replace) is only valid for regexp_replace");
53				}
54				break;
55			case ' ':
56			case '\t':
57			case '\n':
58				// ignore whitespace
59				break;
60			default:
61				throw InvalidInputException("Unrecognized Regex option %c", options[i]);
62			}
63		}
64	}
