66	void ParseRegexOptions(ClientContext &context, Expression &expr, RE2::Options &target, bool *global_replace) {
67		if (expr.HasParameter()) {
68			throw ParameterNotResolvedException();
69		}
70		if (!expr.IsFoldable()) {
71			throw InvalidInputException("Regex options field must be a constant");
72		}
73		Value options_str = ExpressionExecutor::EvaluateScalar(context, expr);
74		if (options_str.IsNull()) {
75			throw InvalidInputException("Regex options field must not be NULL");
76		}
77		if (options_str.type().id() != LogicalTypeId::VARCHAR) {
78			throw InvalidInputException("Regex options field must be a string");
79		}
80		ParseRegexOptions(StringValue::Get(options_str), target, global_replace);
81	}
