83	void ParseGroupNameList(ClientContext &context, const string &function_name, Expression &group_expr,
84	                        const string &pattern_string, RE2::Options &options, bool require_constant_pattern,
85	                        vector<string> &out_names, child_list_t<LogicalType> &out_struct_children) {
86		if (group_expr.HasParameter()) {
87			throw ParameterNotResolvedException();
88		}
89		if (!group_expr.IsFoldable()) {
90			throw InvalidInputException("Group specification field must be a constant list");
91		}
92		Value list_val = ExpressionExecutor::EvaluateScalar(context, group_expr);
93		if (list_val.IsNull() || list_val.type().id() != LogicalTypeId::LIST) {
94			throw BinderException("Group specification must be a non-NULL LIST");
95		}
96		auto &children = ListValue::GetChildren(list_val);
97		if (children.empty()) {
98			throw BinderException("Group name list must be non-empty");
99		}
100		case_insensitive_set_t name_set;
101		for (auto &child : children) {
102			if (child.IsNull()) {
103				throw BinderException("NULL group name in %s", function_name);
104			}
105			auto name = child.ToString();
106			if (name_set.find(name) != name_set.end()) {
107				throw BinderException("Duplicate group name '%s' in %s", name, function_name);
108			}
109			name_set.insert(name);
110			out_names.push_back(name);
111			out_struct_children.emplace_back(make_pair(name, LogicalType::VARCHAR));
112		}
113		if (require_constant_pattern) {
114			duckdb_re2::StringPiece const_piece(pattern_string.c_str(), pattern_string.size());
115			RE2 constant_re(const_piece, options);
116			auto group_cnt = constant_re.NumberOfCapturingGroups();
117			if (group_cnt == -1) {
118				throw BinderException("Pattern failed to parse: %s", constant_re.error());
119			}
120			if ((idx_t)group_cnt < out_names.size()) {
121				throw BinderException("Not enough capturing groups (%d) for provided names (%llu)", group_cnt,
122				                      NumericCast<uint64_t>(out_names.size()));
123			}
124		}
125	}
