127	// Advance exactly one UTF-8 codepoint starting at 'base'. Falls back to single byte on invalid lead.
128	// Does not do a full validation of UTF-8 sequence, assumes input is mostly valid UTF-8.
129	idx_t AdvanceOneUTF8Basic(const duckdb_re2::StringPiece &input, idx_t base) {
130		if (base >= input.length()) {
131			return 1; // Out of bounds, just advance one byte
132		}
133		unsigned char first = static_cast<unsigned char>(input[base]);
134		idx_t char_len = 1;
135		if ((first & 0x80) == 0) {
136			char_len = 1; // ASCII
137		} else if ((first & 0xE0) == 0xC0) {
138			char_len = 2;
139		} else if ((first & 0xF0) == 0xE0) {
140			char_len = 3;
141		} else if ((first & 0xF8) == 0xF0) {
142			char_len = 4;
143		} else {
144			// This should be impossible since RE2 operates on codepoints
145			throw InternalException("Invalid UTF-8 lead byte in regexp_extract_all");
146		}
147		if (base + char_len > input.length()) {
148			throw InternalException("Invalid UTF-8 sequence in regexp_extract_all");
149		}
150		return char_len;
151	}
