123	struct RegexStringPieceArgs {
124		RegexStringPieceArgs() : size(0), capacity(0), group_buffer(nullptr) {
125		}
126		void Init(idx_t size) {
127			this->size = size;
128			// Allocate for one extra, for the all-encompassing match group
129			this->capacity = size + 1;
130			group_buffer = AllocateArray<duckdb_re2::StringPiece>(capacity);
131		}
132		void SetSize(idx_t size) {
133			this->size = size;
134			if (size + 1 > capacity) {
135				Clear();
136				Init(size);
137			}
138		}
139	
140		RegexStringPieceArgs &operator=(RegexStringPieceArgs &&other) noexcept {
141			this->size = other.size;
142			this->capacity = other.capacity;
143			this->group_buffer = other.group_buffer;
144			other.size = 0;
145			other.capacity = 0;
146			other.group_buffer = nullptr;
147			return *this;
148		}
149	
150		~RegexStringPieceArgs() {
151			Clear();
152		}
153	
154	private:
155		void Clear() {
156			DeleteArray<duckdb_re2::StringPiece>(group_buffer, capacity);
157			group_buffer = nullptr;
158	
159			size = 0;
160			capacity = 0;
161		}
162	
163	public:
164		idx_t size;
165		//! The currently allocated capacity for the groups
