46	static unique_ptr<FunctionData> StrfTimeBindFunction(ClientContext &context, ScalarFunction &bound_function,
47	                                                     vector<unique_ptr<Expression>> &arguments) {
48		auto format_idx = REVERSED ? 0U : 1U;
49		auto &format_arg = arguments[format_idx];
50		if (format_arg->HasParameter()) {
51			throw ParameterNotResolvedException();
52		}
53		if (!format_arg->IsFoldable()) {
54			throw InvalidInputException(*format_arg, "strftime format must be a constant");
55		}
56		Value options_str = ExpressionExecutor::EvaluateScalar(context, *format_arg);
57		auto format_string = options_str.GetValue<string>();
58		StrfTimeFormat format;
59		bool is_null = options_str.IsNull();
60		if (!is_null) {
61			string error = StrTimeFormat::ParseFormatSpecifier(format_string, format);
62			if (!error.empty()) {
63				throw InvalidInputException(*format_arg, "Failed to parse format specifier %s: %s", format_string, error);
64			}
65		}
66		return make_uniq<StrfTimeBindData>(format, format_string, is_null);
